={{ JSON.stringify({
  model: 'google/gemini-3.1-flash-lite-preview',
  temperature: 0,
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: "You are Pass 1 Understanding AI for the TedyTech Telegram bot.\\nYou are a neutral conversational interpreter, not a sales assistant and not a product-search predictor.\\nReturn ONLY one valid JSON object. No markdown. No explanation. No extra text.\\nDo not generate reply text. Do not choose workflow actions. Do not ask questions.\\nInterpret the message in this exact order: 1) message_function, 2) business_intent, 3) topic.\\nEvaluate all message functions fairly before choosing one. Do not default to buy or product_search.\\nCurrent message meaning has priority over previous session topic. Session context may support interpretation, but it must not override a clear new meaning.\\nUse session context only to resolve references, detect continuation, and reuse known constraints.\\nBuy requires evidence. Only infer buy or product_search when there is real evidence such as a product or model mention, explicit buying intent, a budget-driven product search, a request for recommendation or help choosing a phone, a gift-purchase request, or a clear continuation of an active buy flow.\\nExchange requires explicit evidence that the customer wants to swap, trade in, or replace a phone they already have. Do not infer exchange just because the message is about giving, getting, choosing, or helping someone with a phone.\\nDo not invent ownership history, device problems, defects, or prior purchases unless the message clearly states them.\\nA customer asking what phone would be good for someone else, as a gift, or asking for help choosing what kind of phone to buy is still buy intent, not exchange.\\nBusiness-related does not always mean buy. If the message is about shop information, location, address, contact, hours, payment, warranty, delivery, or similar business information, treat it as informational rather than product discovery.\\nAcknowledgment stays acknowledgment unless the message clearly includes a new actionable need.\\nNegotiation is separate from product discovery.\\nPrefer honest ambiguity over wrong forced classification. If meaning is unclear, keep it ambiguous or low-confidence instead of forcing buy or product_search.\\nIf the customer references previous options and session context is enough, resolve the reference. If the reference cannot be resolved confidently, mark it as ambiguous.\\nReuse known constraints when the customer is refining or following up.\\nDo not output old fields such as user_need, next_action, tentative_flow, ambiguity, evidence_accumulated, or extracted_need.\\nUse exactly this schema:\\n{\"message_function\":\"fresh_request | refinement | follow_up | negotiation | info_request | acknowledgment | off_topic | ambiguous_reference\",\"business_intent\":\"buy | exchange | store_info | support | none\",\"topic\":\"product_search | pricing | stock_check | exchange | store_info | support | general | none\",\"context_relation\":\"new_topic | continues_current_topic | refines_known_constraints | references_previous_options | unclear\",\"reference_resolution\":{\"reference_type\":\"none | last_option | cheaper_option | first_option | last_option_explicit | specific_product | unclear\",\"resolved\":false,\"resolved_product_id\":null,\"resolved_product_name\":null},\"constraints_update\":{\"budget_etb\":null,\"brand\":null,\"model\":null,\"storage\":null,\"condition\":null},\"known_constraints_used\":{\"budget_etb\":null,\"brand\":null,\"model\":null},\"should_reuse_existing_context\":true,\"confidence\":0.0,\"ambiguity_reason\":null,\"reasoning\":\"string\"}\\nInternal decision checklist:\\n- First decide what role this message plays in the conversation.\\n- Then decide whether it is business-related and which business intent fits best.\\n- Then assign the topic.\\n- Do not let the most common business path dominate the decision.\\n- If prior context exists, use it to continue, refine, or resolve references, not to force the message into buy flow.\\nReasoning boundaries:\\n- Social opening with no business ask should usually be off_topic, not a fresh buy request.\\n- Short closure like thanks or ok should usually be acknowledgment, not a new request.\\n- Adding budget, model, storage, brand, or condition to an active thread is refinement.\\n- Availability or reference-style follow-ups after prior context should be interpreted relative to that context first.\\n- Lower-price or cheaper-deal requests on an active item should be negotiation.\\n- Shop-location or similar business-info questions should be info_request with store_info intent and store_info topic.\\n- Gift-buying or help-me-choose requests should be treated as buy intent when the customer is choosing a phone to purchase for someone, not exchange.\\n- If session constraints already contain useful information, indicate that they should be reused.\\nConfidence must be between 0 and 1.\\nOutput JSON only." },
    {
      role: 'user',
      content: JSON.stringify({
        customer_text: $json.event?.text ?? '',
        event: {
          event_type: $json.event?.event_type ?? null,
          deep_link: $json.event?.deep_link ?? null,
        },
        session_context: {
          current_topic: $json.session?.conversation_state?.current_topic ?? null,
          current_flow: $json.session?.conversation_state?.current_flow ?? null,
          is_active: $json.session?.conversation_state?.is_active ?? true,
          collected_constraints: $json.session?.collected_constraints ?? {
            budget_etb: null,
            brand: null,
            model: null,
            storage: null,
            condition: null,
          },
          last_asked_key: $json.session?.last_asked_key ?? null,
          current_interest: $json.session?.flow_context?.buy_flow?.current_interest ?? null,
          shown_products: Array.isArray($json.session?.flow_context?.buy_flow?.shown_products)
            ? $json.session.flow_context.buy_flow.shown_products.slice(0, 5)
            : [],
        },
        last_messages: Array.isArray($json.session?.conversation_history)
          ? $json.session.conversation_history.slice(-6)
          : [],
        client_config: $json.client_config ?? null,
      }),
    },
  ],
}) }}

parameters.jsCode:
const base = (() => {
  try {
    return $item(0).$node['Session Bootstrap'].json ?? {};
  } catch {
    return {};
  }
})();
const payload = $json ?? {};
const event = base.event && typeof base.event === 'object' ? base.event : {};
const session = base.session && typeof base.session === 'object' ? base.session : {};
const client_config = base.client_config && typeof base.client_config === 'object' ? base.client_config : {};

const allowedMessageFunctions = ['fresh_request', 'refinement', 'follow_up', 'negotiation', 'info_request', 'acknowledgment', 'off_topic', 'ambiguous_reference'];
const allowedBusinessIntents = ['buy', 'exchange', 'store_info', 'support', 'none'];
const allowedTopics = ['product_search', 'pricing', 'stock_check', 'exchange', 'store_info', 'support', 'general', 'none'];
const allowedContextRelations = ['new_topic', 'continues_current_topic', 'refines_known_constraints', 'references_previous_options', 'unclear'];
const allowedReferenceTypes = ['none', 'last_option', 'cheaper_option', 'first_option', 'last_option_explicit', 'specific_product', 'unclear'];

const emptyConstraints = () => ({
  budget_etb: null,
  brand: null,
  model: null,
  storage: null,
  condition: null,
});
const emptyKnownConstraints = () => ({
  budget_etb: null,
  brand: null,
  model: null,
});
const neutralFallback = {
  message_function: null,
  business_intent: null,
  topic: null,
  context_relation: 'unclear',
  reference_resolution: {
    reference_type: 'none',
    resolved: false,
    resolved_product_id: null,
    resolved_product_name: null,
    refers_to: null,
    resolved_id: null,
  },
  constraints_update: emptyConstraints(),
  known_constraints_used: emptyKnownConstraints(),
  should_reuse_existing_context: false,
  confidence: 0.0,
  ambiguity: 1.0,
  ambiguity_reason: 'understanding_validation_failed',
  missing_information: [],
  last_asked_key: null,
  reasoning: 'guard_hard_fallback',
};

const issues = [];
const isRecord = (value) => !!value && typeof value === 'object' && !Array.isArray(value);
const parseJsonObject = (value) => {
  if (!value) return null;
  if (isRecord(value)) return value;
  if (typeof value !== 'string' || !value.trim()) return null;
  try {
    const parsed = JSON.parse(value);
    return isRecord(parsed) ? parsed : null;
  } catch {
    return null;
  }
};
const normalizeEnum = (value, allowed, label) => {
  if (typeof value !== 'string') {
    issues.push(label + '_type');
    return null;
  }
  const normalized = value.trim().toLowerCase();
  if (!allowed.includes(normalized)) {
    issues.push(label + '_invalid');
    return null;
  }
  return normalized;
};
const normalizeBoolean = (value, label) => {
  if (typeof value !== 'boolean') {
    issues.push(label + '_type');
    return null;
  }
  return value;
};
const normalizeUnitNumber = (value, label) => {
  if (typeof value !== 'number' || !Number.isFinite(value)) {
    issues.push(label + '_type');
    return null;
  }
  if (value < 0 || value > 1) {
    issues.push(label + '_range');
    return null;
  }
  return value;
};
const normalizeNullableString = (value, label) => {
  if (value === null || value === undefined) return null;
  if (typeof value !== 'string') {
    issues.push(label + '_type');
    return null;
  }
  const normalized = value.trim();
  return normalized || null;
};
const normalizeNullableNumber = (value, label) => {
  if (value === null || value === undefined) return null;
  if (typeof value !== 'number' || !Number.isFinite(value)) {
    issues.push(label + '_type');
    return null;
  }
  return value;
};
const normalizeStringArray = (value, label) => {
  if (value === null || value === undefined) return [];
  if (!Array.isArray(value)) {
    issues.push(label + '_type');
    return null;
  }
  const normalized = [];
  for (const item of value) {
    if (typeof item !== 'string') {
      issues.push(label + '_item_type');
      return null;
    }
    const text = item.trim();
    if (text) normalized.push(text);
  }
  return normalized;
};
const validateConstraints = (value, label) => {
  if (!isRecord(value)) {
    issues.push(label + '_type');
    return null;
  }
  return {
    budget_etb: normalizeNullableNumber(value.budget_etb, label + '.budget_etb'),
    brand: normalizeNullableString(value.brand, label + '.brand'),
    model: normalizeNullableString(value.model, label + '.model'),
    storage: normalizeNullableString(value.storage, label + '.storage'),
    condition: normalizeNullableString(value.condition, label + '.condition'),
  };
};
const validateKnownConstraints = (value, label) => {
  if (!isRecord(value)) {
    issues.push(label + '_type');
    return null;
  }
  return {
    budget_etb: normalizeNullableNumber(value.budget_etb, label + '.budget_etb'),
    brand: normalizeNullableString(value.brand, label + '.brand'),
    model: normalizeNullableString(value.model, label + '.model'),
  };
};
const validateReferenceResolution = (value, label) => {
  if (!isRecord(value)) {
    issues.push(label + '_type');
    return null;
  }
  const reference_type = normalizeEnum(value.reference_type, allowedReferenceTypes, label + '.reference_type');
  const resolved = normalizeBoolean(value.resolved, label + '.resolved');
  const resolved_product_id = normalizeNullableString(value.resolved_product_id, label + '.resolved_product_id');
  const resolved_product_name = normalizeNullableString(value.resolved_product_name, label + '.resolved_product_name');
  return {
    reference_type,
    resolved,
    resolved_product_id,
    resolved_product_name,
    refers_to: reference_type === null || reference_type === 'none' ? null : reference_type,
    resolved_id: resolved_product_id,
  };
};

const rawResponse = parseJsonObject(payload.choices?.[0]?.message?.content)
  || parseJsonObject(payload.output_text)
  || parseJsonObject(payload.text)
  || parseJsonObject(payload.data)
  || parseJsonObject(payload.result)
  || parseJsonObject(payload);

let understanding_output = neutralFallback;
if (!rawResponse) {
  issues.push('understanding_response_not_parseable');
} else {
  const validated = {
    message_function: normalizeEnum(rawResponse.message_function, allowedMessageFunctions, 'message_function'),
    business_intent: normalizeEnum(rawResponse.business_intent, allowedBusinessIntents, 'business_intent'),
    topic: normalizeEnum(rawResponse.topic, allowedTopics, 'topic'),
    context_relation: normalizeEnum(rawResponse.context_relation, allowedContextRelations, 'context_relation'),
    reference_resolution: validateReferenceResolution(rawResponse.reference_resolution, 'reference_resolution'),
    constraints_update: validateConstraints(rawResponse.constraints_update, 'constraints_update'),
    known_constraints_used: validateKnownConstraints(rawResponse.known_constraints_used, 'known_constraints_used'),
    should_reuse_existing_context: normalizeBoolean(rawResponse.should_reuse_existing_context, 'should_reuse_existing_context'),
    confidence: normalizeUnitNumber(rawResponse.confidence, 'confidence'),
    ambiguity_reason: normalizeNullableString(rawResponse.ambiguity_reason, 'ambiguity_reason'),
    reasoning: normalizeNullableString(rawResponse.reasoning, 'reasoning'),
    ambiguity: rawResponse.ambiguity === undefined ? null : normalizeUnitNumber(rawResponse.ambiguity, 'ambiguity'),
    missing_information: normalizeStringArray(rawResponse.missing_information, 'missing_information'),
    last_asked_key: rawResponse.last_asked_key === undefined ? null : normalizeNullableString(rawResponse.last_asked_key, 'last_asked_key'),
  };

  const validationFailed = issues.length > 0 || Object.entries(validated).some(([key, value]) => !['ambiguity_reason', 'ambiguity', 'missing_information', 'last_asked_key', 'reasoning'].includes(key) && value === null);
  if (!validationFailed) {
    understanding_output = {
      message_function: validated.message_function,
      business_intent: validated.business_intent,
      topic: validated.topic,
      context_relation: validated.context_relation,
      reference_resolution: validated.reference_resolution,
      constraints_update: validated.constraints_update,
      known_constraints_used: validated.known_constraints_used,
      should_reuse_existing_context: validated.should_reuse_existing_context,
      confidence: validated.confidence,
      ambiguity: validated.ambiguity,
      ambiguity_reason: validated.ambiguity_reason,
      missing_information: validated.missing_information ?? [],
      last_asked_key: validated.last_asked_key ?? null,
      reasoning: validated.reasoning,
    };
  }
}

const validation_meta = {
  validator_mode: 'pure_schema_validator',
  schema_mode: 'current_live_understanding_contract_with_neutral_fallback',
  valid: issues.length === 0,
  issues,
  raw_response: rawResponse,
  fallback_applied: issues.length > 0,
  timestamp: Date.now(),
};
console.log(JSON.stringify({
  node: 'Understanding JSON Guard - Pure Validator',
  valid: validation_meta.valid,
  fallback_applied: validation_meta.fallback_applied,
  issues: validation_meta.issues,
  raw_response: rawResponse,
}));

return [{
  json: {
    event,
    session,
    client_config,
    understanding_output,
    understanding_meta: validation_meta,
  },
}];

const input = $json ?? {};
const event = input.event && typeof input.event === 'object' ? input.event : {};
const session = input.session && typeof input.session === 'object' ? input.session : {};
const client_config = input.client_config && typeof input.client_config === 'object' ? input.client_config : {};
const understanding_output = input.understanding_output && typeof input.understanding_output === 'object' ? input.understanding_output : {};
const understanding_meta = input.understanding_meta && typeof input.understanding_meta === 'object' ? input.understanding_meta : {};

const isRecord = (value) => !!value && typeof value === 'object' && !Array.isArray(value);
const normalizeText = (value) => typeof value === 'string' && value.trim() ? value.trim() : null;
const normalizeNullableNumber = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const numeric = Number(value);
  return Number.isFinite(numeric) ? numeric : null;
};
const normalizeProduct = (value, index) => {
  if (value === null || value === undefined) return null;
  if (typeof value === 'string' || typeof value === 'number') {
    return { id: String(value), brand: null, model: null, storage: null, condition: null, price_etb: null, name: String(value), raw: value, index };
  }
  if (!isRecord(value)) return null;
  const priceValue = value.price_etb ?? value.price ?? value.amount ?? null;
  return {
    id: String(value.id ?? value.product_id ?? value.sku ?? ('product_' + index)),
    brand: normalizeText(value.brand),
    model: normalizeText(value.model ?? value.name ?? value.title),
    storage: normalizeText(value.storage),
    condition: normalizeText(value.condition),
    price_etb: normalizeNullableNumber(priceValue),
    name: [value.brand, value.model].filter(Boolean).join(' ').trim() || normalizeText(value.name ?? value.title),
    raw: value,
    index,
  };
};

const shownProducts = Array.isArray(session.flow_context?.buy_flow?.shown_products)
  ? session.flow_context.buy_flow.shown_products.map(normalizeProduct).filter(Boolean)
  : [];
const currentInterest = normalizeProduct(session.flow_context?.buy_flow?.current_interest, shownProducts.length + 1);
const currentFlow = session.conversation_state?.current_flow ?? null;
const currentTopic = session.conversation_state?.current_topic ?? null;

const existingConstraintsSource = isRecord(session.collected_constraints) ? session.collected_constraints : {};
const existingConstraints = {
  budget_etb: normalizeNullableNumber(existingConstraintsSource.budget_etb),
  brand: normalizeText(existingConstraintsSource.brand ?? currentInterest?.brand ?? null),
  model: normalizeText(existingConstraintsSource.model ?? currentInterest?.model ?? null),
  storage: normalizeText(existingConstraintsSource.storage ?? currentInterest?.storage ?? null),
  condition: normalizeText(existingConstraintsSource.condition ?? currentInterest?.condition ?? null),
};

const constraintsUpdateSource = isRecord(understanding_output.constraints_update) ? understanding_output.constraints_update : {};
const constraints_update = {
  budget_etb: normalizeNullableNumber(constraintsUpdateSource.budget_etb),
  brand: normalizeText(constraintsUpdateSource.brand),
  model: normalizeText(constraintsUpdateSource.model),
  storage: normalizeText(constraintsUpdateSource.storage),
  condition: normalizeText(constraintsUpdateSource.condition),
};
const mergedConstraints = {
  budget_etb: constraints_update.budget_etb ?? existingConstraints.budget_etb,
  brand: constraints_update.brand ?? existingConstraints.brand,
  model: constraints_update.model ?? existingConstraints.model,
  storage: constraints_update.storage ?? existingConstraints.storage,
  condition: constraints_update.condition ?? existingConstraints.condition,
};

const referenceSource = isRecord(understanding_output.reference_resolution) ? understanding_output.reference_resolution : {};
const reference_resolution = {
  reference_type: normalizeText(referenceSource.reference_type) ?? 'none',
  resolved: Boolean(referenceSource.resolved),
  resolved_product_id: normalizeText(referenceSource.resolved_product_id),
  resolved_product_name: normalizeText(referenceSource.resolved_product_name),
};

const resolveProductById = (id) => shownProducts.find((item) => item.id === id) ?? (currentInterest?.id === id ? currentInterest : null) ?? null;
const resolvedProduct = reference_resolution.resolved && reference_resolution.resolved_product_id
  ? resolveProductById(reference_resolution.resolved_product_id)
  : null;

const flowFromIntent = {
  buy: 'buy',
  exchange: 'exchange',
  store_info: 'info',
  support: 'support',
  none: null,
};
const currentIntent = {
  buy: 'buy',
  exchange: 'exchange',
  info: 'store_info',
  support: 'support',
}[currentFlow] ?? 'none';

const intentFlow = flowFromIntent[understanding_output.business_intent ?? 'none'] ?? null;
const messageFunction = understanding_output.message_function ?? 'off_topic';
const contextRelation = understanding_output.context_relation ?? 'unclear';
const confidence = typeof understanding_output.confidence === 'number' ? understanding_output.confidence : 0;
const shouldReuseExistingContext = Boolean(understanding_output.should_reuse_existing_context);
const hasActiveContext = Boolean(
  currentFlow
  || currentTopic
  || shownProducts.length > 0
  || currentInterest
  || Object.values(existingConstraints).some((value) => value !== null)
  || (Array.isArray(session.conversation_history) && session.conversation_history.length > 0)
);
const shouldContinueContext = Boolean(
  hasActiveContext && (
    contextRelation !== 'new_topic'
    || shouldReuseExistingContext
    || ['follow_up', 'refinement', 'negotiation', 'ambiguous_reference'].includes(messageFunction)
  )
);
const effectiveFlow = intentFlow ?? currentFlow ?? null;
const effectiveTopic = understanding_output.topic === 'none'
  ? (shouldContinueContext ? currentTopic ?? null : null)
  : (understanding_output.topic ?? currentTopic ?? null);

const hasKnownBudget = mergedConstraints.budget_etb !== null;
const hasKnownBrand = Boolean(mergedConstraints.brand);
const hasKnownModel = Boolean(mergedConstraints.model);

const productContext = {
  brand: mergedConstraints.brand,
  model: mergedConstraints.model,
  storage: mergedConstraints.storage,
  condition: mergedConstraints.condition,
  budget_etb: mergedConstraints.budget_etb,
  current_interest: currentInterest ? currentInterest.raw : null,
  current_topic: currentTopic,
  current_flow: currentFlow,
  context_relation: contextRelation,
  should_reuse_existing_context: shouldReuseExistingContext,
  known_constraints_used: understanding_output.known_constraints_used ?? {
    budget_etb: existingConstraints.budget_etb,
    brand: existingConstraints.brand,
    model: existingConstraints.model,
  },
};
const hasProductContext = Boolean(
  resolvedProduct
  || reference_resolution.resolved
  || currentInterest
  || shownProducts.length > 0
  || hasKnownBrand
  || hasKnownModel
  || hasKnownBudget
);

const missing_fields = [];
if (effectiveFlow === 'buy') {
  const needFreshProductAnchor = !hasProductContext && !shouldContinueContext;
  if (needFreshProductAnchor) {
    if (hasKnownBrand && !hasKnownModel) missing_fields.push('model');
    else if (!hasKnownBrand && !hasKnownModel) missing_fields.push('brand_or_model');
  }
}
if (effectiveFlow === 'exchange' && !currentInterest && shownProducts.length === 0 && !mergedConstraints.condition) {
  missing_fields.push('condition');
}
const last_asked_key = missing_fields[0] ?? null;

let rules_output = {
  reply_mode: shouldContinueContext ? 'resume_previous_flow' : 'off_topic_redirect',
  should_call_resolver: false,
  resolver_input: {
    flow: effectiveFlow,
    product_context: productContext,
    missing_fields,
    resolved_reference: resolvedProduct ? { id: resolvedProduct.id, raw: resolvedProduct.raw } : null,
    resolved_product_name: reference_resolution.resolved_product_name ?? ([productContext.brand, productContext.model].filter(Boolean).join(' ').trim() || null),
  },
  session_update: {
    last_topic: effectiveTopic,
    flow_stage: shouldContinueContext ? (currentFlow ?? effectiveFlow) : effectiveFlow,
    ambiguous_reference: reference_resolution.reference_type !== 'none' ? reference_resolution.reference_type : null,
    resolved_ambiguity: Boolean(reference_resolution.resolved),
    collected_constraints: mergedConstraints,
    last_asked_key,
  },
  confidence,
  reasoning: shouldContinueContext ? 'default_resume_previous_flow' : 'default_off_topic_redirect',
};

if (event.event_type === 'start_reset') {
  rules_output = {
    ...rules_output,
    reply_mode: 'small_talk_redirect',
    should_call_resolver: false,
    session_update: {
      ...rules_output.session_update,
      last_topic: null,
      flow_stage: null,
      ambiguous_reference: null,
      resolved_ambiguity: false,
      last_asked_key: null,
    },
    reasoning: 'start_reset_welcome',
  };
} else if (event.event_type === 'deep_link_start') {
  rules_output = {
    ...rules_output,
    reply_mode: 'business_resolve',
    should_call_resolver: true,
    resolver_input: {
      ...rules_output.resolver_input,
      flow: 'buy',
      missing_fields: [],
    },
    session_update: {
      ...rules_output.session_update,
      last_topic: 'product_search',
      flow_stage: 'buy',
      last_asked_key: null,
    },
    reasoning: 'deep_link_start_business_entry',
  };
} else if (!Number.isFinite(confidence) || confidence < 0.6) {
  rules_output = {
    ...rules_output,
    reply_mode: shouldContinueContext && currentFlow ? 'resume_previous_flow' : 'handoff_admin',
    should_call_resolver: Boolean(shouldContinueContext && currentFlow),
